self.addEventListener("push",n=>{if(n.data)try{let i=n.data.json(),t=i.title||"Vinayak Tuition Classes",e={body:i.body||"",icon:"/logo.png",badge:"/logo.png",data:{url:i.url||"/"}};n.waitUntil(self.registration.showNotification(t,e))}catch(n){console.error("Error handling push event:",n)}}),self.addEventListener("notificationclick",n=>{n.notification.close();let i=new URL(n.notification.data?.url||"/",self.location.origin).href;n.waitUntil(self.clients.matchAll({type:"window",includeUncontrolled:!0}).then(n=>{for(let t of n)if(t.url===i&&"focus"in t)return t.focus();if(self.clients.openWindow)return self.clients.openWindow(i)}))});